// // This is a 4-to-16 decoder that takes a 4-bit binary input and outputs a 16-bit line corresponding to the binary value of the input. However, only one of the output lines will be low (logic 0) at any time, with all others high (logic 1).
module decoder_4_to_16 (
    input [3:0] A,
    output reg [15:0] Y
);
    always @(*) begin
        Y = 16'b0; // Default output
        Y[A] = 1'b1; // Set the corresponding output line high
    end
endmodule
